code.styles.css:
* {
  box-sizing: border-box;
}
body {
  background: #fff;
  min-height: 100vh;
  padding: 0;
  margin: 0;
}

.nav {
  position: fixed;
  padding: 2em;
  width: 100%;
  text-align: center;
  z-index: 1000000;
  color: #fff;
  mix-blend-mode: difference;
  font-family: "Neue Montreal";
  font-size: 1rem;
  display: flex;
  justify-content: space-between;
}

.gallery {
  position: absolute;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

.cards {
  position: absolute;
  width: 75vw;
  height: 50rem;
  top: 75%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.cards li {
  list-style: none;
  padding: 0;
  margin: 0;
  width: 75vw;
  height: 50rem;
  position: absolute;
  top: 0;
  left: 0;
}

li:nth-child(1) {
  background: url(./images/img-1.png) no-repeat 50% 50%;
  background-size: cover;
}

